console.log("[D] 点击了编辑按钮");

$Variable.modifySpaceTimeRepo = !$Variable.modifySpaceTimeRepo;

// debugger;


// main();

function main()
{
    const currentData = $Variable.currentSpaceTimeRepo;
    if (Object.keys(currentData).length === 0)
    {
        _showMessage("请选择想要删除的实例", "warning");
        return;
    }

    if (currentData.guid === $Variable.工程Root时空仓库GUID)
    {
        _showMessage("实例根仓库不允许删除", "warning");
        return;
    }
    
    if(currentData.instancetype === "1")
    {
        _showMessage("子实例不允许删除", "warning");
        return;
    }

    showChildPage();
}



function showChildPage()
{

    debugger;

    const clientHeight = document.body.clientHeight;
    const clientWidth = document.body.clientWidth;

    const pageHeight = 200;
    const pageWidth = 400;

    const pageLeft = (clientWidth - pageWidth) / 2;
    const pageTop = (clientHeight - pageHeight) / 2 - 100;

    const styleOptions = {
        width: pageWidth,
        height: pageHeight,
        left: pageLeft,
        top: pageTop,
        draggable: false,
        header: false,
        // title: pageTitle,
        closable: true,
        resizable: false,
        maximizable: false,
    };

    const pageName = $Variable.删除实例页面名称;

    const variables = [
        {
            name: "配置后台时空对象全路径",
            value: $Variable.配置后台时空对象全路径
        },
        {
            name: "配置后台APP对象名称",
            value: $Variable.配置后台APP对象名称
        },
        {
            name: "cloudId",
            value: $Variable.cloudId
        },
        {
            name: "实例信息",
            value: $Variable.currentSpaceTimeRepo
        },
        {
            name: "实例根仓库GUID",
            value: $Variable.工程Root时空仓库GUID
        }
    ];

    const options = {
        styleOptions,
        variables,
        stType: 5, // 2：FULLNAME
        spaceTime: $Variable.配置后台时空对象全路径
    };

    debugger;

    ShowChild(pageName, options, function (transferData)
    {
        publicEventHanlder(pageName, transferData);
    });
}

function publicEventHanlder(pageName, transferData)
{
    console.log(`[D] <实例化框架页面> 接收到 <${pageName}> 传递来的公开事件 transferData = `, transferData);

    const {
        eventName,
        eventParam
    } = transferData;


    if (eventName === "Cancel")
    {
        CloseChild(pageName);
        return;
    }
    else if (eventName === "Confirm")
    {
        // $Variable.isUpdateViewTable = !$Variable.isUpdateViewTable;
        // $Variable.updateInstanceTreeView = !$Variable.updateInstanceTreeView;
        debugger;

        if ($Variable.spaceTimeRepoKeyWords.length === 0)
        {
            const parentNodeGuid = $Variable.currentSpaceTimeRepo.parentguid;
            console.log("[D] 被删除节点的父节点 guid = ", parentNodeGuid);
            spaceTimeRepo_ElementTree.SetCurrentKey(parentNodeGuid);
            const parentNode = spaceTimeRepo_ElementTree.GetCurrentNode();
            console.log("[D] 获取到当前选中的节点 parentNode = ", parentNode);
            $Variable.currentSpaceTimeRepo = { ...parentNode };
        }
        else
        {
            $Variable.currentSpaceTimeRepo = {};
            $Variable.updateTreeByFilter = !$Variable.updateTreeByFilter;
        }
        CloseChild(pageName);
        return;
    }
}


function _showMessage(massage, type = "error")
{
    var options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true,
    };
    ShowMessage(options);
}

