        return;
    }

    $Variable.submitSpaceTimeRepos = {
        spaceTimeRepoGuids: [currentData.guid],
        versionInstruction: versionInstruction,
    };



}

async function _showInstructionPage(pageName)
{
    const clientWidth = document.body.clientWidth;
    const clientHeight = document.body.clientHeight;

    const pageWidth = clientWidth > 360 ? 360 : clientWidth * 0.9;
    const pageHeight = clientHeight > 180 ? 180 : clientHeight * 0.9;

    const pageLeft = (clientWidth - pageWidth - 40) / 2;
    const pageTop = (clientHeight - pageHeight - 34) / 2;

    const styleOptions = {
        width: pageWidth,
        height: pageHeight,
        left: pageLeft,
        top: pageTop,
        draggable: false,
        header: false,
        // title: pageTitle,
        closable: true,
        resizable: false,
        maximizable: false,
        topPadding: "17px",
        bottomPadding: "17px",
        leftPadding: "20px",
        rightPadding: "20px"
    };

    const variables = [];
    const options = {
        styleOptions,
        variables,
        stType: 5, // 2：FULLNAME
        spaceTime: $Variable.配置后台时空对象全路径
    };
    return new Promise(resolve =>
    {
        ShowChild(pageName, options, function (transferData)
        {
            console.log(`[D] <实例化框架页面> :: 接收到 <${pageName}> 传递来的公开事件 transferData = `, transferData);
            const { eventName, eventParam } = transferData;
            if (eventName == "Confirm")
            {
                resolve(eventParam[0]);
                CloseChild(pageName);
                return;
            }
            if (eventName === "Cancel")
            {
                resolve();
                CloseChild(pageName);
                return;
            }
        });
    });
}

